import React, { useState } from "react"
import { Check, ChevronsUpDown } from "lucide-react"
import { cn } from "@/shadcn/lib/utils"
import { Button } from "@/shadcn/components/ui/button"
import { Popover, PopoverContent, PopoverTrigger } from "@/shadcn/components/ui/popover"
import {
    Command, CommandEmpty, CommandGroup, CommandInput, CommandItem, CommandList,
} from "@/shadcn/components/ui/command"
import type { FieldOption } from "@/components/forms/HarmonyForm"

interface HarmonyComboboxProps {
    options: FieldOption[]
    value: string
    onChange: (v: string) => void
    placeholder?: string
    disabled?: boolean
    error?: boolean
    renderOption?: (opt: FieldOption) => React.ReactNode
    renderSelected?: (opt: FieldOption) => React.ReactNode
    renderGroupHeader?: (groupName: string, groupId?: string) => React.ReactNode
}

export function HarmonyCombobox({
    options,
    value,
    onChange,
    placeholder = "Select...",
    disabled = false,
    error = false,
    renderOption,
    renderSelected,
    renderGroupHeader,
}: HarmonyComboboxProps) {
    const [open, setOpen] = useState(false)
    const selected = options.find(o => String(o.value) === value)
    const isGrouped = options.some(o => o.group)

    const groupMap = new Map<string, { groupId?: string; items: FieldOption[] }>()
    if (isGrouped) {
        for (const opt of options) {
            const key = opt.group ?? ''
            if (!groupMap.has(key)) groupMap.set(key, { groupId: opt.groupId, items: [] })
            groupMap.get(key)!.items.push(opt)
        }
    }

    const renderTriggerContent = () => {
        if (!selected) return placeholder
        if (renderSelected) return renderSelected(selected)
        if (renderOption) return renderOption(selected)
        return selected.label
    }

    const renderItems = (items: FieldOption[]) => items.map(opt => (
        <CommandItem
            key={String(opt.value)}
            value={[opt.group, opt.label].filter(Boolean).join(' ')}
            onSelect={() => {
                onChange(String(opt.value))
                setOpen(false)
            }}
        >
            <span className="h-4 w-4 shrink-0" />
            {renderOption ? renderOption(opt) : opt.label}
            <Check
                className={cn(
                    "ml-auto h-4 w-4 shrink-0",
                    value === String(opt.value) ? "opacity-100" : "opacity-0"
                )}
            />
        </CommandItem>
    ))

    return (
        <Popover open={open} onOpenChange={setOpen}>
            <PopoverTrigger asChild>
                <Button
                    type="button"
                    variant="outline"
                    role="combobox"
                    aria-expanded={open}
                    aria-invalid={error ? true : undefined}
                    disabled={disabled}
                    className={cn(
                        "w-full justify-between font-normal h-9",
                        !selected && "text-muted-foreground",
                        disabled && "cursor-not-allowed"
                    )}
                >
                    <span className="flex items-center gap-2 truncate min-w-0">
                        {renderTriggerContent()}
                    </span>
                    <ChevronsUpDown className="ml-2 h-4 w-4 shrink-0 opacity-50" />
                </Button>
            </PopoverTrigger>
            <PopoverContent
                className="w-[var(--radix-popover-trigger-width)] p-0"
                align="start"
            >
                <Command>
                    <CommandInput placeholder="Search..." />
                    <CommandList>
                        <CommandEmpty>No results found.</CommandEmpty>
                        {isGrouped ? (
                            Array.from(groupMap.entries()).map(([groupName, { groupId, items }]) => (
                                <CommandGroup key={groupName || '__ungrouped'}>
                                    {groupName && (
                                        <div className="px-2 pt-2 pb-1 text-sm font-semibold text-foreground flex items-center gap-2">
                                            {renderGroupHeader
                                                ? renderGroupHeader(groupName, groupId)
                                                : groupName}
                                        </div>
                                    )}
                                    {renderItems(items)}
                                </CommandGroup>
                            ))
                        ) : (
                            <CommandGroup>
                                {renderItems(options)}
                            </CommandGroup>
                        )}
                    </CommandList>
                </Command>
            </PopoverContent>
        </Popover>
    )
}
