import { useState } from "react"
import { Building2 } from "lucide-react"
import { cn } from "@/shadcn/lib/utils"

interface CustomerLogoProps {
  customerId?: string | null
  className?: string
}

export function CustomerLogo({ customerId, className }: CustomerLogoProps) {
  const [imgError, setImgError] = useState(false)
  const src = (customerId && !imgError)
    ? `${import.meta.env.VITE_API_BASE_URL}/customers/${customerId}/logo`
    : undefined

  return (
    <div className={cn(
      "shrink-0 rounded-md border border-border bg-muted/50 flex items-center justify-center overflow-hidden",
      className
    )}>
      {src
        ? <img src={src} alt="" className="h-full w-full object-cover" onError={() => setImgError(true)} />
        : <Building2 className="size-1/2 text-muted-foreground/50" />
      }
    </div>
  )
}
